import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.HashMap;
import java.util.List;

public class TestUrlDecodeFunctionWithCharset extends AbstractFunctionStringTestBase {

    @Test
    public void testUrlDecodeWithCharsetParameter() throws Exception {
        // Test case 1: url_decode with ISO-8859-1 encoding
        String transformSql1 = "select url_decode(string1, 'ISO-8859-1') from source";
        TransformConfig config1 = new TransformConfig(transformSql1);
        TransformProcessor<String, String> processor1 = TransformProcessor
                .create(config1, SourceDecoderFactory.createCsvDecoder(csvSource),
                        SinkEncoderFactory.createKvEncoder(kvSink));

        // Test with ISO-8859-1 encoded string
        String iso88591Encoded = URLEncoder.encode("testéàç", "ISO-8859-1");
        List<String> output1 = processor1.transform(
                iso88591Encoded + "|banana|cloud|1", new HashMap<>());
        Assert.assertEquals(1, output1.size());
        // Expected: should decode correctly with ISO-8859-1
        Assert.assertEquals("result=testéàç", output1.get(0));

        // Test case 2: url_decode with UTF-8 encoding (default)
        String transformSql2 = "select url_decode(string1) from source";
        TransformConfig config2 = new TransformConfig(transformSql2);
        TransformProcessor<String, String> processor2 = TransformProcessor
                .create(config2, SourceDecoderFactory.createCsvDecoder(csvSource),
                        SinkEncoderFactory.createKvEncoder(kvSink));

        // Test with UTF-8 encoded string
        String utf8Encoded = URLEncoder.encode("testéàç", StandardCharsets.UTF_8.toString());
        List<String> output2 = processor2.transform(
                utf8Encoded + "|banana|cloud|1", new HashMap<>());
        Assert.assertEquals(1, output2.size());
        // Expected: should decode correctly with UTF-8 (the current default)
        Assert.assertEquals("result=testéàç", output2.get(0));

        // Test case 3: Test with null charset parameter (should default to UTF-8)
        String transformSql3 = "select url_decode(string1, null) from source";
        TransformConfig config3 = new TransformConfig(transformSql3);
        TransformProcessor<String, String> processor3 = TransformProcessor
                .create(config3, SourceDecoderFactory.createCsvDecoder(csvSource),
                        SinkEncoderFactory.createKvEncoder(kvSink));

        List<String> output3 = processor3.transform(
                utf8Encoded + "|banana|cloud|1", new HashMap<>());
        Assert.assertEquals(1, output3.size());
        // Expected: should default to UTF-8 when charset is null
        Assert.assertEquals("result=testéàç", output3.get(0));
    }

    @Test(expected = Exception.class)
    public void testUrlDecodeWithInvalidCharset() throws Exception {
        // This test should fail with current implementation since it doesn't support charset parameter
        String transformSql = "select url_decode(string1, 'INVALID_CHARSET') from source";
        TransformConfig config = new TransformConfig(transformSql);
        TransformProcessor<String, String> processor = TransformProcessor
                .create(config, SourceDecoderFactory.createCsvDecoder(csvSource),
                        SinkEncoderFactory.createKvEncoder(kvSink));

        // This should throw an exception because invalid charset is not supported
        processor.transform("test%20string|banana|cloud|1", new HashMap<>());
    }

    @Test
    public void testUrlDecodeMultipleParameters() throws Exception {
        // Test that url_decode function can handle multiple parameters (string and charset)
        String transformSql = "select url_decode(string1, 'UTF-8') from source";
        TransformConfig config = new TransformConfig(transformSql);
        TransformProcessor<String, String> processor = TransformProcessor
                .create(config, SourceDecoderFactory.createCsvDecoder(csvSource),
                        SinkEncoderFactory.createKvEncoder(kvSink));

        String utf8Encoded = URLEncoder.encode("hello world", StandardCharsets.UTF_8.toString());
        List<String> output = processor.transform(
                utf8Encoded + "|banana|cloud|1", new HashMap<>());
        Assert.assertEquals(1, output.size());
        // Expected: should decode correctly with UTF-8
        Assert.assertEquals("result=hello world", output.get(0));
    }
}

